// Code under test is generated by sqlc; this test file pins the expected
// public surface so an accidental rename or removal during regeneration
// breaks the build instead of silently breaking callers in 03-03..03-08.
package gen

import (
	"context"
	"reflect"
	"testing"

	"github.com/jackc/pgx/v5/pgtype"
)

// TestUpstreams_QuerierSurface guarantees that the 6 query methods exposed
// by the generated Queries type for the ai_gateway.upstreams table are
// present and have the expected signatures (Plan 03-02 Task 2).
//
// The test does NOT exercise the database — it only verifies symbol shape
// via reflection so callers can rely on the surface without a live PG.
func TestUpstreams_QuerierSurface(t *testing.T) {
	q := (*Queries)(nil)

	// :many — Phase 11.2 (D-B5′): sqlc now emits per-query Row structs
	// because the SELECT list explicitly enumerates columns (including
	// tier_priority added by migration 0029). The element types are
	// ListEnabledUpstreamsRow / ListAllUpstreamsRow respectively, both
	// of which carry a TierPriority int32 field.
	manyReturns := map[string]reflect.Type{
		"ListEnabledUpstreams": reflect.TypeOf(ListEnabledUpstreamsRow{}),
		"ListAllUpstreams":     reflect.TypeOf(ListAllUpstreamsRow{}),
	}
	for name, wantElem := range manyReturns {
		m, ok := reflect.TypeOf(q).MethodByName(name)
		if !ok {
			t.Errorf("missing method %s on *Queries", name)
			continue
		}
		if m.Type.NumIn() != 2 {
			t.Errorf("%s: NumIn=%d want 2", name, m.Type.NumIn())
		}
		if m.Type.NumOut() != 2 {
			t.Errorf("%s: NumOut=%d want 2", name, m.Type.NumOut())
		}
		if got := m.Type.Out(0); got.Kind() != reflect.Slice || got.Elem() != wantElem {
			t.Errorf("%s: Out(0)=%v want []%v", name, got, wantElem)
		}
	}

	// :one — Phase 11.2: GetUpstreamByName returns GetUpstreamByNameRow
	// (same TierPriority-bearing struct shape).
	if m, ok := reflect.TypeOf(q).MethodByName("GetUpstreamByName"); !ok {
		t.Error("missing method GetUpstreamByName")
	} else {
		if m.Type.NumIn() != 3 { // receiver + ctx + name
			t.Errorf("GetUpstreamByName: NumIn=%d want 3", m.Type.NumIn())
		}
		if got := m.Type.In(2); got.Kind() != reflect.String {
			t.Errorf("GetUpstreamByName: In(2)=%v want string", got)
		}
		if got := m.Type.Out(0); got != reflect.TypeOf(GetUpstreamByNameRow{}) {
			t.Errorf("GetUpstreamByName: Out(0)=%v want GetUpstreamByNameRow", got)
		}
	}

	// :exec — return error, input (ctx, ParamsStruct)
	for name, paramsType := range map[string]reflect.Type{
		"UpdateUpstreamProbe": reflect.TypeOf(UpdateUpstreamProbeParams{}),
		"UpdateUpstreamAdmin": reflect.TypeOf(UpdateUpstreamAdminParams{}),
		"SetUpstreamEnabled":  reflect.TypeOf(SetUpstreamEnabledParams{}),
	} {
		m, ok := reflect.TypeOf(q).MethodByName(name)
		if !ok {
			t.Errorf("missing method %s on *Queries", name)
			continue
		}
		if m.Type.NumIn() != 3 { // receiver + ctx + params
			t.Errorf("%s: NumIn=%d want 3", name, m.Type.NumIn())
		}
		if m.Type.NumOut() != 1 {
			t.Errorf("%s: NumOut=%d want 1", name, m.Type.NumOut())
		}
		if got := m.Type.In(2); got != paramsType {
			t.Errorf("%s: In(2)=%v want %v", name, got, paramsType)
		}
		if got := m.Type.Out(0); got.String() != "error" {
			t.Errorf("%s: Out(0)=%v want error", name, got)
		}
	}
}

// TestUpstreams_AdminParamsAreNullable confirms that UpdateUpstreamAdmin
// uses pgtype.Int4 / pgtype.Bool / []byte for COALESCE-tolerant null
// inputs (Plan 03-02 Task 2 acceptance criterion). gatewayctl upstreams
// update relies on this — passing pgtype.Int4{Valid:false} skips the col.
func TestUpstreams_AdminParamsAreNullable(t *testing.T) {
	p := UpdateUpstreamAdminParams{}
	if reflect.TypeOf(p.Tier) != reflect.TypeOf(pgtype.Int4{}) {
		t.Errorf("UpdateUpstreamAdminParams.Tier = %T, want pgtype.Int4", p.Tier)
	}
	if reflect.TypeOf(p.Enabled) != reflect.TypeOf(pgtype.Bool{}) {
		t.Errorf("UpdateUpstreamAdminParams.Enabled = %T, want pgtype.Bool", p.Enabled)
	}
	if reflect.TypeOf(p.CircuitConfig).Kind() != reflect.Slice {
		t.Errorf("UpdateUpstreamAdminParams.CircuitConfig = %T, want []byte", p.CircuitConfig)
	}
}

// TestUpstreams_ProbeParamsAreNullable confirms that UpdateUpstreamProbe
// uses pgtype.Timestamptz / pgtype.Int4 / pgtype.Text so failed probes
// can persist NULL last_probe_ms / last_probe_error without panicking.
func TestUpstreams_ProbeParamsAreNullable(t *testing.T) {
	p := UpdateUpstreamProbeParams{}
	if reflect.TypeOf(p.LastProbeAt) != reflect.TypeOf(pgtype.Timestamptz{}) {
		t.Errorf("LastProbeAt = %T, want pgtype.Timestamptz", p.LastProbeAt)
	}
	if reflect.TypeOf(p.LastProbeMs) != reflect.TypeOf(pgtype.Int4{}) {
		t.Errorf("LastProbeMs = %T, want pgtype.Int4", p.LastProbeMs)
	}
	if reflect.TypeOf(p.LastProbeStatus) != reflect.TypeOf(pgtype.Text{}) {
		t.Errorf("LastProbeStatus = %T, want pgtype.Text", p.LastProbeStatus)
	}
	if reflect.TypeOf(p.LastProbeError) != reflect.TypeOf(pgtype.Text{}) {
		t.Errorf("LastProbeError = %T, want pgtype.Text", p.LastProbeError)
	}
}

// Compile-time check that *Queries satisfies the Querier interface (which
// includes all upstream methods after sqlc regen).
var _ Querier = (*Queries)(nil)

// Compile-time use of `context` import so this test file builds in
// isolation when go vet checks unused imports during plan execution.
var _ = context.Background
